<template>
  <div>
    <div class="action-container">
      <el-button type="primary" icon="el-icon-circle-plus" @click="handleNew">
        新增內購企業
      </el-button>
    </div>

    <SpFilterForm :model="params" @onSearch="onSearch" @onReset="onSearch">
      <SpFilterFormItem prop="enterprise_name" label="企業名稱:">
        <el-input v-model="params.enterprise_name" placeholder="請輸入企業名稱" />
      </SpFilterFormItem>
    </SpFilterForm>

    <el-table
      v-loading="loading"
      border
      :data="list"
      :height="wheight - 170"
      element-loading-text="數據加載中"
      :default-sort="{ prop: 'bind_date', order: 'descending' }"
    >
      <el-table-column label="ID" prop="enterprise_id" />
      <el-table-column prop="enterprise_name" label="企業名稱" />
      <el-table-column prop="enterprise_sn" label="企業編碼" />

      <el-table-column prop="login_type" label="登錄類型">
        <template slot-scope="scope">
          <span v-if="scope.row.login_type == 'mobile'">手機號碼登錄</span>
          <span v-else-if="scope.row.login_type == 'email'">郵箱登錄</span>
          <span v-else-if="scope.row.login_type == 'account'">帳號登錄</span>
          <span v-else>{{ scope.row.login_type }}</span>
        </template>
      </el-table-column>

      <el-table-column prop="disabled" label="狀態">
        <template slot-scope="scope">
          <el-button type="text" icon="el-icon-s-tools" @click="handleClick(scope.row)">
            {{ scope.row.disabled == 0 ? '啟用' : '停用' }}
          </el-button>
        </template>
      </el-table-column>
      <el-table-column label="操作">
        <template slot-scope="scope">
          <el-button type="text" @click="handleEdit(scope.row)"> 編輯 </el-button>
        </template>
      </el-table-column>
    </el-table>
    <div class="content-padded content-center">
      <el-pagination
        background
        layout="total, sizes, prev, pager, next"
        :current-page.sync="page.pageIndex"
        :page-sizes="[10, 20, 50]"
        :total="total_count"
        :page-size="page.pageSize"
        @current-change="onCurrentChange"
        @size-change="onSizeChange"
      />
    </div>
    <sideBar :visible.sync="show_sideBar" :title="'新增企業'">
      <el-form>
        <el-form-item label="企業名稱">
          <el-input v-model="form.enterprise_name" />
        </el-form-item>
        <el-form-item label="企業編碼">
          <el-input v-model="form.enterprise_sn" />
        </el-form-item>
        <el-form-item label="登錄類型">
          <el-select v-model="form.login_type" style="width: 100%">
            <el-option label="手機號碼" value="mobile" />
            <el-option label="帳號" value="account" />
            <el-option label="郵箱" value="email" />
          </el-select>
        </el-form-item>
        <el-form-item>
          <el-button type="primary" @click="save"> 提交 </el-button>
        </el-form-item>
      </el-form>
    </sideBar>
  </div>
</template>
<script>
import { mapGetters } from 'vuex'
import imgPicker from '@/components/imageselect'
import {
  getEnterpriseList,
  addEnterpriseInfo,
  getEnterpriseDetail,
  updateEnterpriseInfo,
  deteleEnterpriseInfo,
  updateEnterpriseStaus
} from '@/api/member'
import { pageMixin } from '@/mixins'
import { setPaymentSetting, getPaymentSetting } from '@/api/trade'
import sideBar from '@/components/element/sideBar'
export default {
  components: {
    sideBar,
    imgPicker
  },
  mixins: [pageMixin],
  data() {
    return {
      form: {
        enterprise_id: '',
        enterprise_name: '',
        enterprise_sn: '',
        login_type: ''
      },
      params: {
        enterprise_name: ''
      },
      list: [],
      loading: false,
      brand_name: '',
      total_count: 0,
      show_sideBar: false,
      setChinaumspayVisible: false
    }
  },
  mounted() {
    this.fetchList()
  },
  methods: {
    handleNew() {
      this.show_sideBar = true
      this.resetData()
    },
    resetData() {
      this.form = {
        enterprise_id: '',
        enterprise_name: '',
        enterprise_sn: '',
        login_type: ''
      }
    },
    handleEdit(data) {
      this.show_sideBar = true
      this.form = {
        enterprise_id: data.enterprise_id,
        enterprise_name: data.enterprise_name,
        enterprise_sn: data.enterprise_sn,
        login_type: data.login_type
      }
    },
    handleClick(row) {
      const message = row.disabled == 0 ? '是否停用？' : '是否啟用？'
      this.$confirm(message, '通知消息', {
        confirmButtonText: '確定',
        cancelButtonText: '取消',
        type: 'warning',
        center: true
      }).then(async () => {
        const result = await updateEnterpriseStaus(row.enterprise_id, {
          disabled: row.disabled == 1 ? 0 : 1,
          id: row.enterprise_id
        })
        if (result.data.data.status) {
          this.$message({
            type: 'success',
            message: '更新成功!'
          })
          this.fetchList()
          this.resetData()
        }
      })
      console.log(row)
    },
    save() {
      // 如果沒有id，則表示為新增
      if (!this.form.enterprise_id) {
        delete this.form.enterprise_id
        addEnterpriseInfo(this.form).then((res) => {
          this.$message({ type: 'success', message: '操作成功' })
          this.page.pageIndex = 1
          this.resetData()
          this.fetchList()
        })
      } else {
        updateEnterpriseInfo(this.form.enterprise_id, this.form).then((res) => {
          this.$message({ type: 'success', message: '操作成功' })
          this.fetchList()
          this.setChinaumspayVisible = false
        })
      }
    },
    fetchList() {
      this.loading = true
      const { pageIndex: page, pageSize } = this.page
      let params = {
        page,
        pageSize,
        ...this.params
      }
      getEnterpriseList(params).then((res) => {
        this.list = res.data.data.list
        this.total_count = res.data.data.total_count
        this.loading = false
      })
      console.log(this.list)
    }
  },
  computed: {
    ...mapGetters(['wheight'])
  }
}
</script>
<style scoped lang="scss">
.upload-box {
  width: 100px;
  height: 100px;
  .avatar-uploader-icon {
    line-height: 100px;
  }
}
.sp-filter-form {
  margin-bottom: 16px;
}
</style>
